import React from 'react'
import ZionForm, { useWatch, useZionForm } from '@fs/zion-form'
import * as Yup from 'yup'
import { yupResolver } from '@hookform/resolvers/yup'
import { useHistory } from '@fs/zion-router'
import { useTranslation } from 'react-i18next'
import { MarginBox } from '@fs/zion-ui'
import CreateGroupContent from './CreateGroupContent'
import CreateGroupActions from './CreateGroupActions'
import { useChatDispatch, useChatState } from '../../providers/ChatStateProvider'
import { updateChannelInChannels } from '../../helpers/stream/streamChatHelper'
import {
  createPublicChannel,
  removeIllegalChannelNameCharacters,
  isChannelNameValidRegex,
} from '../../services/fsChat/fsChatService'
import { CHAT_ACTIONS } from '../../hooks/useChatReducer'
import useHandleChatErrors from '../../hooks/useHandleChatErrors'
import useChatLog from '../../hooks/useChatLog'
import { buildChatRoute, CHAT_ROUTE_KEY } from '../../chat-memory-router/ChatMemoryRouter'
import { addOrRemoveChannelMembers } from '../../hooks/channelHooks'

export default function ChatCreateGroup() {
  const [t] = useTranslation()
  const history = useHistory()
  const { channels, client } = useChatState()
  const chatDispatch = useChatDispatch()
  const { log, track } = useChatLog({ component: '[ChatCreateGroup]' })

  const validationSchema = Yup.object().shape({
    createGroupName: Yup.string()
      .required('')
      .matches(isChannelNameValidRegex, t('chat.error-invalid-symbols-in-name.message', 'Cannot contain symbols')),
  })

  const methods = useZionForm({
    mode: 'all',
    resolver: yupResolver(validationSchema),
    defaultValues: { createGroupName: '', createGroupDescription: '' },
  })

  const createGroupName = useWatch({ name: 'createGroupName', control: methods.control })

  const { handleChatCreateGroupError } = useHandleChatErrors({ supportInformation: { name: createGroupName }, log })

  const onCreateChat = async (values) => {
    try {
      const name = values.createGroupName || ''
      const description = removeIllegalChannelNameCharacters(values.createGroupDescription)
      track({ link_name: `Chat:Create Public Chat` }, { chatChannelName: name })
      const { cid } = await createPublicChannel({ name, description, client, log })
      const [channel] = await client.queryChannels({ cid: { $eq: cid } })
      await addOrRemoveChannelMembers({ cid: channel.cid, cisIdsToAdd: [client?.user?.fs_cis_id], log })
      chatDispatch({ type: CHAT_ACTIONS.SET_CHANNELS, channels: updateChannelInChannels(channels, channel) })
      // ChatDetails tweaks the UI if isNewGroup is in the state
      history.push(buildChatRoute(CHAT_ROUTE_KEY.CHAT_DETAILS, { cid: channel.cid }), { isNewGroup: true })
    } catch (err) {
      handleChatCreateGroupError(err)
    }
  }

  const onCancel = () => history.goBack()

  return (
    <ZionForm methods={methods} onSubmit={onCreateChat} aria-label={t('chat.create-group.action', 'Create Chat')}>
      <MarginBox marginX="sm" marginY="sm">
        <CreateGroupContent />
        <CreateGroupActions disabled={!methods.formState.isValid} onCancel={onCancel} />
      </MarginBox>
    </ZionForm>
  )
}
