import React from 'react'
import { Button, Row } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'

export default function CreateGroupActions({ disabled, onCancel }) {
  const [t] = useTranslation()
  return (
    <Row alignX="end">
      <Button data-testid="cancel-create-group" emphasis="medium" onClick={onCancel}>
        {t('common-ui:cancel.action', 'Cancel')}
      </Button>
      <Button data-testid="create-group" disabled={disabled} emphasis="high" type="submit">
        {t('chat.create-group.action', 'Create Chat')}
      </Button>
    </Row>
  )
}
