import React, { useEffect, useRef } from 'react'
import { useHistory, useParams } from '@fs/zion-router'
import ChatLoadingIndicator from '../chat-window/ChatLoadingIndicator'
import { useChatDispatch, useChatState } from '../providers/ChatStateProvider'
import {
  createRootsTechSessionChannel,
  createRootsTechTopicChannel,
  createVendorChannel,
  createDirectChannel,
} from '../services/fsChat/fsChatService'
import { CHAT_ACTIONS } from '../hooks/useChatReducer'
import { updateChannelInChannels, upperCaseCisId } from '../helpers/stream/streamChatHelper'
import { LOG_LEVEL } from '../global/chatLog'
import useHandleChatErrors from '../hooks/useHandleChatErrors'
import { CHANNEL_TYPE } from '../services/fsChat/fsChannelEnums'
import useChatLog from '../hooks/useChatLog'
import { CHAT_ROUTE_KEY, buildChatRoute } from '../chat-memory-router/ChatMemoryRouter'
import { addOrRemoveChannelMembers } from '../hooks/channelHooks'

async function createSpecialtyChat({ type, supportInformation, cisIds, log }) {
  switch (type) {
    case CHANNEL_TYPE.FS_VENDOR:
      return createVendorChannel({
        name: supportInformation?.name,
        externalId: supportInformation?.externalId,
        eventLabel: supportInformation?.eventLabel,
        description: supportInformation?.description,
        image: supportInformation?.imageUrl,
        log,
      })
    case CHANNEL_TYPE.FS_SESSION:
      return createRootsTechSessionChannel({
        name: supportInformation?.name,
        description: supportInformation?.description,
        externalId: supportInformation?.externalId,
        eventLabel: supportInformation?.eventLabel,
        log,
      })
    case CHANNEL_TYPE.FS_ROOTSTECH:
      return createRootsTechTopicChannel({
        name: supportInformation?.name,
        description: supportInformation?.description,
        cisIds,
        log,
      })
    case CHANNEL_TYPE.FS_DIRECT:
      return createDirectChannel({
        cisIds: supportInformation?.to ? [...supportInformation.to] : [],
        log,
      })
    default:
      log({ msg: `Type '${type}' not handled in createSupportChat`, level: LOG_LEVEL.ERROR })
      throw new Error(`Type '${type}' not handled in createSupportChat`)
  }
}

export default function ChatCreateSpecialtyGroup({ supportInformation }) {
  const history = useHistory()
  const { type } = useParams()
  const { channels, client, isEmbedded, channelsLoading } = useChatState()
  const chatDispatch = useChatDispatch()
  const { log, track } = useChatLog({ component: '[ChatCreateSpecialtyGroup]' })
  const { handleChatCreateGroupError } = useHandleChatErrors({ supportInformation, log })
  const hasSubmittedRef = useRef()

  useEffect(() => {
    let isLatestRender = true
    const channelListLoaded = !channelsLoading || isEmbedded
    const onCreateChat = async () => {
      try {
        track(
          {
            link_name: `Chat:Create Specialty Chat:${type}`,
          },
          { chatChannelName: supportInformation?.name, chatTargetUserIds: supportInformation?.to }
        )
        let cisIds = [client?.user?.fs_cis_id, ...(supportInformation?.to || [])]
          .filter((id) => !!id)
          .map(upperCaseCisId)
        // Do not add members to embedded session channels, which can be viewed without being a member
        if (isEmbedded && type === CHANNEL_TYPE.FS_SESSION) {
          cisIds = []
        }
        const { cid } = await createSpecialtyChat({ type, supportInformation, user: client?.user, cisIds, log })
        const [channel] = await client.queryChannels({ cid: { $eq: cid } })
        if (channel && isLatestRender) {
          if (!isEmbedded && channel.type === CHANNEL_TYPE.FS_SESSION) {
            await addOrRemoveChannelMembers({ cid: channel.cid, cisIdsToAdd: [client?.user?.fs_cis_id], log })
          }
          chatDispatch({ type: CHAT_ACTIONS.SET_CHANNELS, channels: updateChannelInChannels(channels, channel) })
          history.replace(buildChatRoute(CHAT_ROUTE_KEY.CHAT, { cid: channel.cid }))
        }
      } catch (err) {
        handleChatCreateGroupError(err, {}, history)
      }
    }

    if (!hasSubmittedRef.current && client?.user && channelListLoaded) {
      hasSubmittedRef.current = true
      onCreateChat()
    }
    return () => {
      isLatestRender = false
    }
  }, [
    log,
    track,
    handleChatCreateGroupError,
    history,
    chatDispatch,
    supportInformation,
    type,
    channels,
    client,
    isEmbedded,
    channelsLoading,
  ])

  return <ChatLoadingIndicator />
}
