import React from 'react'
import { Route, Switch } from '@fs/zion-router'
import { css } from '@linaria/core'
import { ShadowScroller } from '@fs/zion-ui/quarks-authorized-use-only'
import ChatCreateChat, { ChatCreateDirectChat } from './chat-create-chat/ChatCreateChat'
import ChatCreateGroup from './chat-create-group/ChatCreateGroup'
import ChatCreateSpecialtyGroup from './ChatCreateSpecialtyGroup'
import { buildChatRoute, CHAT_ROUTE_KEY } from '../chat-memory-router/ChatMemoryRouter'
import AUAComposer from './AUAComposer'

const chatCreateCss = css`
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  flex-shrink: 1;
  flex-grow: 1;
  overflow: hidden;
`

export default function ChatCreate({ supportInformation }) {
  return (
    <div className={chatCreateCss}>
      <ShadowScroller>
        <Switch>
          <Route exact path={buildChatRoute(CHAT_ROUTE_KEY.CREATE_EMPTY_DIRECT_CHAT)} component={ChatCreateChat} />
          <Route exact path={buildChatRoute(CHAT_ROUTE_KEY.CREATE_EMPTY_GROUP_CHAT)} component={ChatCreateGroup} />
          <Route exact path={buildChatRoute(CHAT_ROUTE_KEY.CREATE_DIRECT_CHAT)}>
            <ChatCreateDirectChat supportInformation={supportInformation} />
          </Route>
          <Route exact path="/chat-create/fs_support">
            <AUAComposer />
          </Route>
          <Route exact path="/chat-create/:type">
            <ChatCreateSpecialtyGroup supportInformation={supportInformation} />
          </Route>
        </Switch>
      </ShadowScroller>
    </div>
  )
}
