import { HelpAskQuestion } from '@fs/zion-icon'
import { i18n } from '@fs/zion-locale'
import { useHistory } from '@fs/zion-router'
import { H2, LayoutBand, MarginBox, Row, Separator, colors } from '@fs/zion-ui'
import React, { useCallback, useEffect, useRef } from 'react'
import { useTranslation } from 'react-i18next'
import ChatActionsHolder from '../chat-actions/ChatActionsHolder'
import { ChatAttachmentDropContainer } from '../chat-attachments/ChatAttachmentDropContainer'
import { CHAT_ROUTE_KEY, buildChatRoute } from '../chat-memory-router/ChatMemoryRouter'
import { scrollChannelListItemIntoView } from '../chat-window/chat-window-chats/ChatChannelListItem'
import { updateChannelInChannels } from '../helpers/stream/streamChatHelper'
import useChatLog from '../hooks/useChatLog'
import { CHAT_ACTIONS } from '../hooks/useChatReducer'
import useHandleChatErrors from '../hooks/useHandleChatErrors'
import { useChatChannelExpander } from '../providers/ChatChannelExpanderProvider'
import { useChatDispatch, useChatState } from '../providers/ChatStateProvider'
import { useChatProviderContext } from '../providers/useChatProviderContext'
import { CHANNEL_TYPE } from '../services/fsChat/fsChannelEnums'
import { createAUAChannel } from '../services/fsChat/fsChatService'
import { CHAT_PREF, setChatPreference } from '../services/chatUserPreferenceService/chatUserPreferenceService'
import { LOG_LEVEL } from '../global/chatLog'

export function getGroupEnding() {
  const date = new Date()
  const dateSubString = date.toString().substring(4, 22)
  const dateStringWithoutColon = dateSubString.replace(/:/g, '')
  const ampm = date.getHours() < 12 ? 'a' : 'p'
  return `${dateStringWithoutColon}${ampm}`
}

export default function AUAComposer() {
  const [t] = useTranslation()
  const recipientLabel = t('chat.ask-us-anything.heading', 'Ask Us Anything - RootsTech')
  const history = useHistory()
  const { channels, client, channelsLoading, showEvents, preferencesLoaded } = useChatState()
  const chatDispatch = useChatDispatch()
  const { log, track } = useChatLog({ component: '[AUAComposer]' })
  const { handleChatCreateGroupError } = useHandleChatErrors({ log })
  const { setSupportInformation } = useChatProviderContext()

  const { expandable, expandableLoaded, updateExpandableItem } = useChatChannelExpander()
  const isAUAExpanded = expandable[CHANNEL_TYPE.FS_SUPPORT]
  const checkedShowEventsRef = useRef(false)
  const checkedAUAExpandedRef = useRef(false)

  // One-time check to show event chats and expand AUA if needed after preferences have loaded
  useEffect(() => {
    if (preferencesLoaded && !checkedShowEventsRef.current) {
      checkedShowEventsRef.current = true
      if (!showEvents) {
        chatDispatch({ type: CHAT_ACTIONS.SHOW_EVENTS, showEvents: true })
        setChatPreference(CHAT_PREF.SHOW_EVENT_CHATS, true).catch(() => {})
      }
    }
    if (expandableLoaded && !checkedAUAExpandedRef.current) {
      checkedAUAExpandedRef.current = true
      if (!isAUAExpanded) {
        updateExpandableItem({ isOpen: true, key: CHANNEL_TYPE.FS_SUPPORT })
      }
    }
  }, [chatDispatch, expandableLoaded, isAUAExpanded, preferencesLoaded, showEvents, updateExpandableItem])

  // Scroll to AUA once channels have loaded
  useEffect(() => {
    if (channelsLoading) return () => {}

    let intervalId
    const timeoutId = setTimeout(() => {
      const auaElement = document.querySelector('[data-testid="chat-list-item-fs_support"]')
      intervalId = scrollChannelListItemIntoView({ current: auaElement })
    }, 500)
    return () => {
      clearTimeout(timeoutId)
      if (intervalId) clearInterval(intervalId)
    }
  }, [channelsLoading])

  const onSend = useCallback(
    async (text, attachments) => {
      try {
        track({ link_name: `Chat:Create Specialty Chat:fs_support in Language: ${i18n.language}` })
        if (!client?.user?.name) {
          log(
            {
              msg: 'Attempted to create AUA channel without user name',
              level: LOG_LEVEL.ERROR,
            },
            { user: client?.user, wsIsHealthy: client?.wsConnection?.isHealthy }
          )
          throw new Error('User name is required to create AUA channel')
        }
        const name = `${client.user.name} - ${getGroupEnding()}`

        // Support has requested that Ukrainian chats get sent to the Russian help queue.
        // If we support Ukrainian as an official AUA language in the future, this should be removed.
        const language = i18n.language === 'uk' ? 'ru' : i18n.language
        const { cid } = await createAUAChannel({ name, language, log })

        const [channel] = await client.queryChannels({ cid: { $eq: cid } })
        if (!channel) {
          throw new Error('Failed to load created AUA channel')
        }

        await channel.sendMessage({ text, attachments })

        chatDispatch({ type: CHAT_ACTIONS.SET_CHANNELS, channels: updateChannelInChannels(channels, channel) })
        setSupportInformation({})
        history.replace(buildChatRoute(CHAT_ROUTE_KEY.CHAT, { cid: channel.cid }))
      } catch (err) {
        handleChatCreateGroupError(err, {}, history)
        throw err
      }
    },
    [channels, chatDispatch, client, handleChatCreateGroupError, history, setSupportInformation, track, log]
  )

  return (
    <ChatAttachmentDropContainer>
      <MarginBox marginX="xs" marginY="sm">
        <LayoutBand maxWidth="nano">
          <Row alignY="middle" gutters="xs">
            <HelpAskQuestion background={colors.blue30} noShrinkX />
            <H2 size="H5">{t('chat.ask-us-anything.heading', 'Ask Us Anything - RootsTech')}</H2>
          </Row>
          <Separator size="xs" />
          <i>
            {t(
              'chat.type-your-ask-us-anything-question.message-2',
              'Welcome to Ask Us Anything by RootsTech. Please type your question below, then a representative will join you shortly.'
            )}
          </i>
        </LayoutBand>
      </MarginBox>
      <Separator growY />
      <ChatActionsHolder onSend={onSend} recipientLabel={recipientLabel} />
    </ChatAttachmentDropContainer>
  )
}
