import React, { useEffect, useRef } from 'react'
import { css } from '@linaria/core'
import { Paragraph, InputChips, MarginBox, Separator, useStatusOverlay } from '@fs/zion-ui'
import { useHistory } from '@fs/zion-router'
import { useTranslation } from 'react-i18next'
import ChatCreateTo from '../ChatCreateTo'
import { useChatDispatch, useChatState } from '../../providers/ChatStateProvider'
import ChatActions from '../../chat-actions/ChatActions'
import { updateChannelInChannels, findMatchingDirectChannel } from '../../helpers/stream/streamChatHelper'
import { CHAT_ACTIONS } from '../../hooks/useChatReducer'
import { createDirectStreamChannel } from '../../services/fsChat/fsChatService'
import { useChatAttachmentsDispatch, actionTypes } from '../../providers/ChatAttachmentsProvider'
import { FS_DIRECT_MAX_PARTICIPANT_COUNT } from '../../services/fsChat/fsChannelEnums'
import useHandleChatErrors from '../../hooks/useHandleChatErrors'
import ChatContent from '../../chat/ChatContent'
import useChatLog from '../../hooks/useChatLog'
import { getUserProfile } from '../../services/userProfile/userProfileService'
import { useChatProviderContext } from '../../providers/useChatProviderContext'
import { CHAT_ROUTE_KEY, buildChatRoute } from '../../chat-memory-router/ChatMemoryRouter'
import { ChatAttachmentDropContainer } from '../../chat-attachments/ChatAttachmentDropContainer'

const createContainerCss = css`
  display: flex;
  flex-direction: column;
  flex-grow: 1;
  justify-content: space-between;
`

async function addParticipantsFromToList({ resetChips, to = [], t, showStatusOverlay }) {
  resetChips()

  // Remove any duplicates
  const uniqueTo = [...new Set(to)]
  const participantCount = uniqueTo?.length

  // Display an error message if there are too many
  if (participantCount > FS_DIRECT_MAX_PARTICIPANT_COUNT - 1) {
    const truncatedMessage = t(
      'chat.create-members-truncated.warning',
      'We’re sorry. Only {maxParticipants} participants are allowed in a private chat.',
      { maxParticipants: FS_DIRECT_MAX_PARTICIPANT_COUNT }
    )
    const missingPeopleMessage = t(
      'chat.missing-people-count.label',
      '{count, plural, =0 {# people were not included in the chat.} one {# person was not included in the chat.} other {# people were not included in the chat.}}',
      { count: participantCount - (FS_DIRECT_MAX_PARTICIPANT_COUNT - 1) }
    )
    showStatusOverlay({
      message: `${truncatedMessage} ${missingPeopleMessage}`,
      type: 'warning',
      dismissable: true,
    })
  }

  if (participantCount > 0) {
    const participants = uniqueTo.slice(0, FS_DIRECT_MAX_PARTICIPANT_COUNT - 1)
    const userProfileResponses = await Promise.allSettled(participants.map((cisId) => getUserProfile(cisId)))
    const newChips = []
    userProfileResponses.forEach((resp) => {
      if (resp.status === 'fulfilled') {
        const participant = resp.value
        const name = participant?.name?.value || 'chat.unknown-name.label'
        newChips.push({
          label: name,
          value: name,
          'aria-label': name,
          dismissAriaLabel: t('common-ui:remove.action', 'Remove'),
          suggestion: {
            globalIndex: 0,
            key: participant?.cisId,
            primaryText: name,
            secondaryText: name,
          },
        })
      }
    })
    resetChips(newChips)
  }
}

export function ChatCreateDirectChat({ supportInformation }) {
  const [t] = useTranslation()
  const showStatusOverlay = useStatusOverlay()
  const { createChatRecipientChipCollection } = useChatState()
  const chatAttachmentsDispatch = useChatAttachmentsDispatch()
  const { resetChips } = createChatRecipientChipCollection
  const to = supportInformation?.to
  const about = supportInformation?.about

  useEffect(() => {
    addParticipantsFromToList({ resetChips, to, t, showStatusOverlay })
  }, [resetChips, showStatusOverlay, t, to])

  useEffect(() => {
    chatAttachmentsDispatch({ type: actionTypes.ADD_PENDING_ABOUT_ATTACHMENT, aboutAttachment: about })
  }, [about, chatAttachmentsDispatch])

  // Since recipient(s) aren’t initially present but will be added async, explicitly auto-focus the message field
  return <ChatCreateChat alwaysAutoFocusMessage />
}

export default function ChatCreateChat({ alwaysAutoFocusMessage = false }) {
  const { client, user, createChatRecipientChipCollection, channels } = useChatState()
  const { setSupportInformation } = useChatProviderContext()
  const chatDispatch = useChatDispatch()
  const history = useHistory()
  const { removeChip, chips } = createChatRecipientChipCollection
  const recipients = chips.map((c) => c.suggestion)
  const [t] = useTranslation()
  const cisIds = recipients.map((r) => {
    const { key: cisId } = r
    return cisId
  })
  if (cisIds.length > 0 && user && !cisIds.find((id) => id === user.cisId)) {
    cisIds.push(user.cisId)
  }
  const channel = findMatchingDirectChannel({ channels, cisIds })
  const userIsInRecipients = user?.cisId && Boolean(cisIds.find((id) => id === user.cisId))
  const recipientLabel = chips.map((c) => c.label).join(', ')
  const { log, track } = useChatLog({ component: '[ChatCreateChat]' })
  const { handleChatCreateChatError } = useHandleChatErrors({ log })

  // Auto-focus message field if we initially have recipients, or explicitly requested
  const messageRef = useRef()
  const checkedFocusRef = useRef(false)
  useEffect(() => {
    if (checkedFocusRef.current) return
    checkedFocusRef.current = true
    if (alwaysAutoFocusMessage || chips.length > 0) {
      setTimeout(() => messageRef.current?.focus(), 0)
    }
  }, [alwaysAutoFocusMessage, chips.length])

  const onCreateChat = async (message, attachments) => {
    try {
      // report how many recipients new message is being sent to
      track(
        { link_name: `Chat:Create Multi-user Chat:Click Send Message (${recipients.length} recipients)` },
        { chatTargetUserIds: cisIds }
      )
      track({ link_name: `Chat:Send Message:fs_direct` }, { chatChannelId: channel?.cid })

      const directChannel = await createDirectStreamChannel({ cisIds, client })
      await directChannel.sendMessage({
        text: message,
        attachments,
      })
      setSupportInformation({})
      chatDispatch({ type: CHAT_ACTIONS.SET_CHANNELS, channels: updateChannelInChannels(channels, directChannel) })
      history.push(buildChatRoute(CHAT_ROUTE_KEY.CHAT, { cid: directChannel.cid }))
    } catch (err) {
      handleChatCreateChatError(err)
    }
  }

  // minus 1 because you are an implicit participant
  const remainingParticipantsAllowedCount = Math.max(FS_DIRECT_MAX_PARTICIPANT_COUNT - chips.length - 1, 0)

  const remainingParticipantsSubHeading = t(
    'chat.remaining-participants-allowed.message',
    '{count, plural, =0 {Your Private Chat is now full. For more than {maxParticipantsCount}, create a Public Chat.} one {You can add # more person.} other {You can add # more people.}}',
    {
      count: remainingParticipantsAllowedCount,
      maxParticipantsCount: FS_DIRECT_MAX_PARTICIPANT_COUNT,
    }
  )

  return (
    <ChatAttachmentDropContainer className={createContainerCss}>
      <div>
        <Separator size="sm" />
        <MarginBox marginX="sm">
          <ChatCreateTo
            disabled={remainingParticipantsAllowedCount <= 0}
            recipientChipCollection={createChatRecipientChipCollection}
          />
          {chips.length > 1 && (
            <>
              <Paragraph size="xs">{remainingParticipantsSubHeading}</Paragraph>
              <Separator size="nano" />
            </>
          )}
          <InputChips onDismiss={removeChip} chipCollection={createChatRecipientChipCollection} />
        </MarginBox>
        <Separator size="xxs" />
      </div>
      <div style={{ flexGrow: 1 }} />
      <ChatContent channel={channel} isCreate />
      <ChatActions
        onSend={onCreateChat}
        overrideDisableSend={!recipients || recipients.length === 0 || !userIsInRecipients}
        messageRef={messageRef}
        recipientLabel={recipientLabel}
      />
    </ChatAttachmentDropContainer>
  )
}
