import React, { useEffect, useRef } from 'react'
import { Trans, useTranslation } from 'react-i18next'
import { PersonBlock, Separator, Alert } from '@fs/zion-ui'
import { useUserProfile } from '@fs/zion-user'
import { Link } from '@fs/zion-router'
import { FormTextArea, FormTextField } from '@fs/zion-form'
import { getPortraitUrlFromCisId } from '../../helpers/portraitServiceHelper'

// This matches the backend channel name limit
const MAX_LENGTH = 100

export default function CreateGroupContent() {
  const [t] = useTranslation()
  const { userProfile } = useUserProfile()
  const profileName = userProfile?.name?.value
  const monogram = profileName ? profileName.charAt(0) : 'U'
  const portraitUrl = getPortraitUrlFromCisId(userProfile?.cisId)

  const focusRef = useRef()
  useEffect(() => {
    // automatically focus the 'Name' input for creating a new group chat
    focusRef?.current?.focus()
  }, [])

  return (
    <>
      <PersonBlock
        size="lg"
        avatarProps={{
          src: portraitUrl,
          monogram,
        }}
        name={profileName || ''}
        details={t('chat.creator.label', 'Creator')}
      />
      <Separator />
      <Alert type="help" dense>
        <Trans
          i18nKey="chat.public-group.label"
          defaults="Public Chats are for topics of general interest. For research questions, try our <0>Help Page</0>. Any RootsTech attendee can join this Public Chat."
          components={[<Link to="https://www.familysearch.org/rootstech/?help" target="_blank" external />]}
        />
      </Alert>
      <FormTextField
        ref={focusRef}
        data-testid="name-textarea"
        name="createGroupName"
        label={t('common-ui:name.person', 'Name')}
        placeholder={t('chat.group-name.placeholder', 'Name your chat')}
        maxLength={MAX_LENGTH}
      />
      <FormTextArea
        data-testid="description-textarea"
        name="createGroupDescription"
        label={t('chat.description-optional.label', 'Description (optional)')}
        placeholder={t('chat.group-description.placeholder', 'What is this chat about?')}
        rows={4}
        disableResize
        maxLength={250}
      />
      <Separator />
    </>
  )
}
